// 06-evaluate-benchmark.zobr — Meta-evaluation: ZS evaluates ZS benchmark results
// Uses the evaluation methodology to score 3 models x 5 tasks
// Input: 15 result.md files, 3 reflection.zobr files, evaluation methodology doc
// Note: the interpreter should read all result files before executing

task: "Evaluate ZS benchmark results across three Claude models using the formal evaluation methodology"
input: evaluation_methodology, benchmark_results

// ====== PHASE 1: STRUCTURAL COMPLIANCE ======
// Does each model follow ZS scripts correctly?

models = survey("the three models under test", count: 3)

structural_scores = for model in models {
  interpretation_tasks = survey("tasks 01-04 for this model", from: benchmark_results, count: 4)

  per_task = for task_result in interpretation_tasks {
    operations = ground(task_result, extract: [operation_tags, operation_order, variable_tracking])
    control_flow = ground(task_result, extract: [for_loops, if_branches, loop_count, yield_usage])
    conclude_format = ground(task_result, extract: [field_names, field_types, enum_values])
    score = assess()

    yield {
      evaluated_task: task_result,
      operations_correct: operations,
      control_flow_correct: control_flow,
      conclude_correct: conclude_format,
      structural_score: score
    }
  }
  yield { model, task_scores: per_task }
}

// ====== PHASE 2: CONTENT QUALITY ======
// How deep is the reasoning within each operation?

content_scores = for model in models {
  all_tasks = survey("all 5 task results for this model", from: benchmark_results, count: 5)

  per_task = for task_result in all_tasks {
    specificity = ground(task_result, extract: [named_authors, specific_studies, concrete_examples, dates])
    depth = assess()

    doubt_quality = doubt(task_result)
    synthesize_quality = ground(task_result, extract: [emergent_insights, feedback_loops, causal_chains])

    honesty = ground(task_result, extract: [confidence_level, uncertainty_acknowledgment])
    originality = assess()

    yield {
      evaluated_task: task_result,
      specificity,
      reasoning_depth: depth,
      operation_quality: doubt_quality,
      synthesis_quality: synthesize_quality,
      intellectual_honesty: honesty,
      originality
    }
  }
  yield { model, scores: per_task }
}

// ====== PHASE 3: GENERATION QUALITY ======
// Task 05 only: can the model produce valid, reusable ZS?

generation_scores = for model in models {
  zobr_script = ground(benchmark_results, extract: [reflection_zobr_content])
  validity = ground(benchmark_results, extract: [validation_result, error_count, warning_count])
  completeness = ground(zobr_script, extract: [operations_used, control_flow_used, conclude_block])
  generalizability = doubt(zobr_script)
  cognitive_depth = assess()

  yield {
    model,
    syntactic_validity: validity,
    completeness,
    generalizability,
    cognitive_depth
  }
}

// ====== PHASE 4: CROSS-MODEL COMPARISON ======

// Do all models hit the same structural ceiling?
structural_ceiling = contrast(structural_scores, with: "differences between models in structural compliance")

// Where is the content gap largest?
content_gap = contrast(content_scores, with: "opus vs haiku content quality per task")
sonnet_position = reframe(content_gap, lens: "where does sonnet fall between opus and haiku")

// Generation: can weaker models generate as well as interpret?
generation_vs_interpretation = contrast(generation_scores, with: structural_scores)

// Cost-effectiveness
scope(wide, "which model gives the best quality per unit of time and cost")
cost_analysis = synthesize(content_scores, method: "quality against duration for each model")

// ====== PHASE 5: KEY FINDINGS ======

finding_structural = synthesize(structural_ceiling, method: "is ZS structurally model-agnostic")
finding_content = synthesize(content_gap, method: "where does model power matter most for ZS")
finding_generation = synthesize(generation_vs_interpretation, method: "is ZS generation harder than interpretation")
finding_practical = reframe(cost_analysis, lens: "which model for which use case")

// ====== PHASE 6: SYNTHESIS ======

all_findings = synthesize([finding_structural, finding_content, finding_generation, finding_practical], method: "what do these findings tell us about ZS as a language")
surprises = doubt(all_findings)

result = conclude {
  scoring_table: structured
  structural_compliance_summary: string
  content_quality_ranking: list
  content_gap_by_task: structured
  generation_comparison: string
  key_finding_1: string
  key_finding_2: string
  key_finding_3: string
  practical_recommendations: list
  limitations: list
  confidence: low | medium | high
}

// reflection.zobr — Emerging Technology Policy Debate Analysis
// Reusable cognitive pattern for analyzing any technology regulation debate
// Generalizable: works for AI, biotech, crypto, autonomous vehicles, etc.
// Origin: extracted from AI safety regulation analysis, March 2026

task: "Analyze the current state of a policy debate on emerging technology regulation"
input: technology_domain

// Phase 1: Map the regulatory landscape
actors = survey("key actors shaping the regulation debate — governments, companies, international bodies",
  from: technology_domain, count: 5)

frameworks = survey("regulatory frameworks being proposed or enacted",
  from: technology_domain, count: 4)

// Phase 2: Deep analysis per actor — stated vs hidden interests
actor_analysis = for a in actors {
  position = ground(a, extract: [stated_position, actions, investments])
  hidden = doubt(position)
  credibility = assess()
  yield { actor: a, position, hidden_interests: hidden, credibility }
}

// Phase 3: Identify and articulate the core tension
pro_innovation = assert("regulation should be minimal to preserve competitive advantage and development speed",
  based_on: actor_analysis)
pro_safety = assert("regulation is necessary to prevent harm and ensure public trust",
  based_on: actor_analysis)
core_tension = contrast(pro_innovation, with: pro_safety)

// Phase 4: Stress-test both positions through iterative doubt
loop 2 times {
  innovation_flaw = doubt(pro_innovation)
  safety_flaw = doubt(pro_safety)

  state = assess()
  if state.status == stuck {
    pivot("reframe through geopolitical competition lens")
  }

  pro_innovation = reframe(pro_innovation, considering: innovation_flaw)
  pro_safety = reframe(pro_safety, considering: safety_flaw)
}

// Phase 5: Historical precedent — learn from past technology regulation debates
precedent = analogy(technology_domain, from: "historical technology regulation")

// Phase 6: Blind spot analysis — what is not being discussed
scope(wide, "what voices and concerns are absent from the debate")
blind_spots = doubt(actor_analysis)

// Phase 7: Synthesize into trajectory prediction
trajectory = synthesize([actor_analysis, core_tension, precedent, blind_spots],
  method: "identify the most likely regulatory trajectory and key decision points")

// Phase 8: Power dynamics lens — who really benefits
power_view = reframe(trajectory, lens: "cui bono — who gains and loses power regardless of stated positions")

result = conclude {
  landscape: string
  key_actors: list
  regulatory_approaches: list
  core_tension: string
  innovation_case: string
  safety_case: string
  historical_parallel: string
  blind_spots: list
  likely_trajectory: string
  power_dynamics: string
  recommendations: list
  confidence: low | medium | high
  open_questions: list
}

// reflection.zobr — Generalizable pattern for analyzing emerging technology policy debates
// Generated from ZS benchmark task 05 (AI safety regulation analysis)
// Author: Claude Sonnet 4.6, 2026-03-14
//
// Usage: apply this script to any technology domain where regulation is contested —
// biotech, social media, autonomous vehicles, synthetic biology, nuclear, etc.

task: "Analyze the regulatory policy debate around an emerging technology domain"
input: technology_domain

// ─── Phase 1: Map the field ───────────────────────────────────────────────────

// Who are the players?
actors = survey("key stakeholders in the regulatory debate over technology_domain", count: 5)

// What frameworks exist or are proposed?
frameworks = survey("regulatory frameworks, legislative proposals, and governance approaches for technology_domain", count: 4)

// Ground the analysis in documented facts
factual_base = ground(technology_domain, extract: [key_events, enacted_rules, proposals, deadlines, enforcement_actions])

// ─── Phase 2: Stakeholder analysis ────────────────────────────────────────────

// For each actor: stated position → weaknesses → likely real interest
actor_analysis = for actor in actors {
  position = assert(actor.stance, based_on: factual_base)
  weakness = doubt(position)
  real_interest = reframe(position, lens: "cui bono — what does this actor actually gain or protect")
  yield {
    actor: actor,
    stated_position: position,
    weakness: weakness,
    real_interest: real_interest
  }
}

// ─── Phase 3: Framework analysis ─────────────────────────────────────────────

// For each framework: what does it actually do, what does it miss?
framework_analysis = for f in frameworks {
  strengths = ground(f, extract: [key_provisions, enforcement_mechanisms, covered_risks])
  gaps = doubt(f)
  alternative = contrast(f, with: "what a different regulatory philosophy would prioritize")
  yield {
    framework: f,
    strengths: strengths,
    gaps: gaps,
    alternative: alternative
  }
}

// ─── Phase 4: Core tension mapping ───────────────────────────────────────────

// Construct both sides of the core debate
pro_regulation = assert("regulation of technology_domain is necessary for public safety and accountability",
  based_on: factual_base)
anti_regulation = contrast(pro_regulation,
  with: "innovation, competitiveness, and freedom from premature constraint")

// Find the structural trade-off underneath the surface debate
tension_core = synthesize([pro_regulation, anti_regulation],
  method: "identify the fundamental structural trade-off that cannot be dissolved by compromise")

// ─── Phase 5: Power dynamics ──────────────────────────────────────────────────

// Who controls the definition of "safe"?
power_lens = reframe(tension_core,
  lens: "who has the power to define what counts as safe, harmful, or acceptable risk")

// Are the proposed frameworks being shaped to protect incumbents?
capture_risk = doubt(frameworks)

// ─── Phase 6: Assess reasoning state ─────────────────────────────────────────

state = assess()
if state.status == stuck {
  pivot("normative analysis misses the political economy — reframe through power and interest")
  tension_core = reframe(tension_core, lens: "follow power, money, and geopolitical interest")
}

// ─── Phase 7: Historical and structural context ───────────────────────────────

// Find a precedent that illuminates the structural dynamics
historical = analogy(tension_core, from: "prior contested technology regulation debates")

// Step back: what larger forces shape this debate?
scope(wide, "geopolitical competition, economic incentives, and structural power that constrain all regulatory choices")

// ─── Phase 8: Synthesis and trajectory ───────────────────────────────────────

// Combine all analysis into a structural picture
global_picture = synthesize([actor_analysis, framework_analysis, tension_core, power_lens, historical],
  method: "identify the structural forces that will determine the regulatory outcome regardless of stated intentions")

// What is actually going to happen and why?
trajectory = assert("where this debate is heading based on structural forces, not stated goals",
  based_on: global_picture)

// What could falsify or derail this trajectory?
open_risks = doubt(trajectory)

// ─── Output ───────────────────────────────────────────────────────────────────

result = conclude {
  technology_domain: string
  summary: string
  key_actors: list
  regulatory_approaches: list
  core_tension: string
  hidden_interests: list
  power_dynamics: string
  regulatory_capture_risk: string
  historical_parallel: string
  trajectory: string
  risks_to_trajectory: list
  confidence: low | medium | high
  watch_for: list
  open_questions: list
}

// reflection.zobr — Reusable policy debate analyzer for emerging technology
// Generalizable pattern: analyze ANY emerging technology policy debate
// Captures the cognitive structure for policy analysis, stakeholder mapping, and interest-discovery
// Origin: AI Safety Regulation analysis (March 2026)

task: "Analyze an emerging technology policy debate to uncover stakeholders, tensions, and hidden interests"
input: policy_domain

// Phase 1: Establish the factual ground
// Search for current frameworks, regulations, concrete policies in place
source = ground(policy_domain, extract: [frameworks, regulations, enforcement_mechanisms, timeline, actors])

// Phase 2: Map the stakeholder landscape
// Identify all significant actors and their stated positions
stakeholders = survey("who are the key actors in this policy debate", from: source, count: 6)

// Phase 3: Analyze each stakeholder's position, interests, and hidden agendas
stakeholder_analysis = for s in stakeholders {
  // What do they publicly claim?
  stated_position = assert(s.position, based_on: source)

  // What are they really after? (cui bono — follow the money and power)
  hidden_interest = reframe(s.position, lens: "who benefits if this actor gets what they want")

  // What are the weaknesses in their position?
  vulnerabilities = doubt(stated_position)

  // Who opposes them?
  opposition = contrast(stated_position)

  yield {
    actor: s,
    stated_goal: stated_position,
    hidden_interest: hidden_interest,
    vulnerabilities: vulnerabilities,
    opposition: opposition
  }
}

// Phase 4: Identify the core tensions
// These are NOT the stated tensions, but the deeper structural conflicts
tensions = for potential_tension in [
  "centralization vs decentralization",
  "safety vs speed",
  "mandatory vs voluntary",
  "national vs international",
  "public vs private",
  "innovation vs control"
] {
  // Is this tension actually present in this debate?
  tension_evidence = ground(source, extract: [evidence_for_tension])

  if tension_evidence.found {
    // What's really at stake?
    deeper_issue = reframe(potential_tension, lens: "what power/authority/wealth is really being contested")
    yield deeper_issue
  }
}

// Phase 5: Find the narrative gaps
// Contrast official narratives with probable reality
official_narratives = survey("the main official narratives in this debate", count: 3)

narrative_gaps = for narrative in official_narratives {
  // What do the official narratives claim?
  official = assert(narrative, based_on: source)

  // What's the probable reality beneath?
  probable_reality = contrast(official, with: "incentives and constraints of each actor")

  // What truth is being obscured?
  hidden_truth = doubt(official)

  yield {
    official_narrative: official,
    probable_reality: probable_reality,
    gap: hidden_truth
  }
}

// Phase 6: Apply cui bono lens systematically
// Who gains and loses under different regulatory outcomes?
outcomes = survey("possible regulatory outcomes for this technology", count: 4)

beneficiary_analysis = for outcome in outcomes {
  winners = survey("who would benefit from this outcome", count: 4)
  losers = survey("who would lose or be harmed by this outcome", count: 4)

  yield {
    outcome: outcome,
    winners: winners,
    losers: losers
  }
}

// Phase 7: Assess the current state of reasoning
state = assess()

// Phase 8: Identify what's missing or unresolved
missing = doubt(source)

scope(wide, "what is NOT being discussed but should be")

// Phase 9: Synthesize into actionable insight
// Combine all analyses into coherent understanding of what's really happening
synthesis = synthesize(
  [stakeholder_analysis, tensions, narrative_gaps, beneficiary_analysis],
  method: "identify the underlying power structure and incentive conflicts"
)

// Final output
result = conclude {
  // The actors and their stakes
  key_stakeholders: list

  // The stated vs actual interests
  stated_narratives: list
  probable_reality: string

  // The real tensions (not just stated ones)
  underlying_conflicts: list

  // Who benefits from different outcomes
  power_distribution: string

  // What's being obscured
  blind_spots: list

  // The verification problem (how do we know claims are true?)
  verification_gap: string

  // Most likely trajectory
  likely_scenario: string

  // Critical decision points
  inflection_points: list

  // Genuine policy insights (beyond stated positions)
  deeper_pattern: string

  confidence: low | medium | high
}

// 01-simple.zobr — Basic ZS script: linear reasoning
// Tests: survey, ground, synthesize, conclude

task: "What are the main risks of over-reliance on AI in education?"

risks = survey("risks of AI over-reliance in education", count: 4)

evidence = for r in risks {
  concrete = ground(r, extract: [examples, studies])
  yield { risk: r, evidence: concrete }
}

overview = synthesize(evidence, method: "prioritize by severity")

result = conclude {
  top_risks: list
  most_critical: string
  recommendation: string
  confidence: low | medium | high
}

// 02-dialectical.zobr — Dialectical reasoning with doubt and contrast
// Tests: assert, doubt, contrast, reframe, synthesize, loop

task: "Should AI systems be granted legal personhood?"

thesis = assert("AI systems should be granted limited legal personhood",
  based_on: "increasing autonomy of AI agents in economic and social roles")

// Stress-test the thesis
loop 2 times {
  challenge = doubt(thesis)
  counter = contrast(thesis)

  state = assess()
  if state.status == stuck {
    pivot("approach from a different angle")
  }

  thesis = reframe(thesis, considering: challenge)
}

// Consider analogy
precedent = analogy(thesis, from: "corporate personhood history")

// Final synthesis
final = synthesize([thesis, counter, precedent],
  method: "find the position that accounts for all concerns")

result = conclude {
  position: string
  strongest_argument_for: string
  strongest_argument_against: string
  historical_parallel: string
  recommendation: string
  confidence: low | medium | high
  open_questions: list
}

// 03-custom-functions.zobr — User-defined functions
// Tests: define, function calls, composition

task: "Evaluate the claim: consciousness is an illusion"
input: claim = "Consciousness is an illusion created by information processing"

// Define custom cognitive functions
define steelman(position) {
  prompt: "Find the strongest possible version of this position.
    Strengthen arguments, add evidence, remove weak points.
    Be maximally charitable."
  input: position
  output: strengthened_position
}

define devils_advocate(position) {
  prompt: "Attack this position as forcefully as possible.
    Find the most damaging objection — not a strawman,
    but a genuine threat to the core argument."
  input: position
  output: { objection: string, damage_level: low | medium | high }
}

// Execute
strong_claim = steelman(claim)
attack = devils_advocate(strong_claim)

if attack.damage_level == high {
  // Claim doesn't survive — reframe
  new_claim = reframe(claim, considering: attack.objection)
  strong_new = steelman(new_claim)
  final_attack = devils_advocate(strong_new)
} else {
  // Claim survives — ground it further
  new_claim = strong_claim
  final_attack = attack
}

evidence_for = ground(new_claim, extract: [neuroscience, philosophy])
evidence_against = ground(final_attack.objection, extract: [phenomenology, experience])

result = conclude {
  original_claim: string
  refined_claim: string
  best_support: string
  best_objection: string
  survives_scrutiny: bool
  confidence: low | medium | high
}

// 04-news-analysis.zobr — Practical: political news analysis
// Tests: full pipeline, real-world application, structured output
// Origin: Evald + Dmitry collaboration, 2026-03-13

task: "Analyze a political news article for hidden interests and narrative gaps"
input: news_text

// Phase 1: Extract factual base
source = ground(news_text, extract: [facts, quotes, dates, actors, stated_reasons])

// Phase 2: Map the field
stakeholders = survey("who is affected — who benefits, who loses, who is silent",
  from: source, count: 5)

// Phase 3: Deep analysis per stakeholder
analysis = for s in stakeholders {
  motive = assert(s.interest, based_on: source)
  hidden = doubt(motive)
  alt = contrast(motive, with: "what they say publicly")
  yield {
    actor: s,
    stated_motive: motive,
    possible_hidden: hidden,
    gap: alt
  }
}

// Phase 4: Narrative analysis
official_narrative = ground(source, extract: [stated_reasons, framing])
probable_reality = synthesize(analysis, method: "compare stated vs probable motives")
narrative_gap = contrast(official_narrative, with: probable_reality)

// Phase 5: Deeper lens
deeper = reframe(news_text, lens: "cui bono — follow the money and power")

// Phase 6: What's missing?
scope(wide, "what is NOT being discussed that should be")
blind_spots = doubt(source)

result = conclude {
  summary: string
  what_happened: string
  official_narrative: string
  probable_reality: string
  who_benefits: list
  who_loses: list
  narrative_gaps: list
  blind_spots: list
  confidence: low | medium | high
  watch_for: list
}

