  "scripts": {
    "build:grammar": "peggy --format es -o src/parser.js src/grammar.pegjs",
    "build:ts": "tsc",
    "build": "npm run build:grammar && npm run build:ts",
    "check": "node dist/cli.js"
  },
  "devDependencies": {
    "@types/node": "^25.5.0",
    "peggy": "^4.2.0",
    "typescript": "^5.7.0"
  },

